import { Box, Flex, Grid, Text, Heading, Link } from "@chakra-ui/react";

const footerData = [
  {
    title: "SRM",
    links: ["About", "Careers", "Blog", "Contact"],
  },
  {
    title: "Learning",
    links: ["Courses", "Categories", "Certificates", "Pricing"],
  },
  {
    title: "Support",
    links: ["Help Center", "Terms", "Privacy", "Accessibility"],
  },
  {
    title: "Explore",
    links: ["Business", "Teach on SRM", "Partners", "Affiliates"],
  },
];

const Footer = () => {
  return (
    <Box bg="#1c1d1f" color="white" px={10} py={16}>
      {/* TOP */}
      <Grid
        templateColumns={{
          base: "1fr",
          md: "repeat(2,1fr)",
          lg: "repeat(4,1fr)",
        }}
        gap={10}
      >
        {footerData.map((section, index) => (
          <Box key={index}>
            <Heading size="sm" mb={4}>
              {section.title}
            </Heading>

            {section.links.map((link, i) => (
              <Text
                key={i}
                fontSize="sm"
                color="gray.400"
                mb={2}
                _hover={{ color: "white", cursor: "pointer" }}
              >
                {link}
              </Text>
            ))}
          </Box>
        ))}
      </Grid>

      {/* BOTTOM */}
      <Flex
        mt={10}
        pt={6}
        borderTop="1px solid #3e4143"
        justify="space-between"
        direction={{ base: "column", md: "row" }}
        align="center"
        gap={4}
      >
        <Text fontSize="sm" color="gray.400">
          © 2026 SRM Inc. All rights reserved.
        </Text>

        <Flex gap={4}>
          <Link fontSize="sm" color="gray.400" _hover={{ color: "white" }}>
            Privacy
          </Link>
          <Link fontSize="sm" color="gray.400" _hover={{ color: "white" }}>
            Terms
          </Link>
          <Link fontSize="sm" color="gray.400" _hover={{ color: "white" }}>
            Sitemap
          </Link>
        </Flex>
      </Flex>
    </Box>
  );
};

export default Footer;
